async (params, browser) => {
  // Search Zillow
  await browser.open(`https://www.zillow.com/homes/${params.query}_rb/`)

  // Wait for search results
  await browser.waitForSelector('[data-test=\'property-card\'], article[class*=\'property\'], [class*=\'ListItem\'], [class*=\'StyledPropertyCard\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract property results
  const search_results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('[data-test="property-card"], article[class*="property"], [class*="ListItem"] article, [class*="StyledPropertyCard"]'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const addressEl = el.querySelector('[data-test="property-card-addr"], address, [class*="address"]'); const priceEl = el.querySelector('[data-test="property-card-price"], [class*="price"], span[class*="Price"]'); const linkEl = el.querySelector('a[href*="/homedetails/"], a[href*="zillow.com"]'); const imgEl = el.querySelector('img'); const bedsEl = el.querySelector('[class*="beds"] b, [class*="beds"], abbr[class*="bed"]'); const bathsEl = el.querySelector('[class*="baths"] b, [class*="baths"], abbr[class*="bath"]'); const sqftEl = el.querySelector('[class*="sqft"] b, [class*="area"], abbr[class*="sqft"]'); const statusEl = el.querySelector('[class*="status"], [class*="listing-tag"], [class*="cardStatus"]'); const detailText = el.textContent || ''; const bdMatch = detailText.match(/(\d+)\s*bd/i); const baMatch = detailText.match(/(\d+)\s*ba/i); const sqftMatch = detailText.match(/([\d,]+)\s*sqft/i); results.push({ address: addressEl ? addressEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', beds: bedsEl ? bedsEl.textContent.trim() : (bdMatch ? bdMatch[1] : ''), baths: bathsEl ? bathsEl.textContent.trim() : (baMatch ? baMatch[1] : ''), sqft: sqftEl ? sqftEl.textContent.trim() : (sqftMatch ? sqftMatch[1] : ''), status: statusEl ? statusEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
